import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"康少校的核弹","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/康少校的核弹.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/康少校的核弹.md"}'),d={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/康少校的核弹.md"};function _(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"康少校的核弹",tabindex:"-1"},[s("康少校的核弹 "),e("a",{class:"header-anchor",href:"#康少校的核弹","aria-label":'Permalink to "康少校的核弹"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序008")])])],-1),o('<h1 id="康少校的核弹-1" tabindex="-1">康少校的核弹 <a class="header-anchor" href="#康少校的核弹-1" aria-label="Permalink to &quot;康少校的核弹&quot;">​</a></h1><p>康少校的核弹<br> C+1000<br> 体积：7<br> 这是一枚B-36国境线守卫机群上搭载的巨型核弹，具有十万吨级当量。这颗核弹上有一架鞍座，可供一名成年男性骑乘。当它启动时将开始自动飞行，而驾驶者需使用一个移动动作以维持核弹平衡，核弹无法停止直至触碰到首个其他单位时会立即产生爆炸或经过一场景仍未爆炸后会自动停止。这颗核弹只是在空中常速飞行，无法做出过于精巧的规避动作，转弯或转向行驶时必须先由骑乘者进行一次力量-运动-专业：平衡检定，难度等同于加速难度，若失败，则无法转向。<br> 核弹的一次移动速度为100米，拥有36点结构值与20点护甲防御，当核弹被击毁时同样会产生爆炸。当核弹产生爆炸时，将如同具有冲撞一般对命中的个体及以核弹为中心，30米半径内的所有角色（包括骑乘者）同时产生冲击波，骑乘的角色需额外消耗一个反射动作和下回合的标准动作，对这次爆炸进行一次以骑乘者基础攻击方式进行的攻击检定，双方受到等同于这次检定伤害出目的伤害，且核弹带有能量武器特性，使用强韧豁免以对抗，冲击波还将同时击退所有在此范围内的角色，使用反射豁免对抗那个伤害出目，并被击退二者差值+45米。当这颗核弹是因被击毁而爆炸时，骑乘者将无需消耗动作，而此次爆炸也不会对自身造成伤害。核弹爆炸后将彻底视为被击毁，在那场影片结束前都不可再用。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
